import sys

class ListNode:
    __slots__ = ('val', 'next')
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def reverseList(self, head: ListNode) -> ListNode:
        prev = None
        cur = head
        while cur:
            nxt = cur.next
            cur.next = prev
            prev = cur
            cur = nxt
        return prev

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    try:
        n = int(next(it))
    except StopIteration:
        sys.exit(0)
    values = []
    for _ in range(n):
        try:
            values.append(int(next(it)))
        except StopIteration:
