#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode* prev = nullptr;
        ListNode* cur = head;
        while (cur) {
            ListNode* nxt = cur->next;
            cur->next = prev;
            prev = cur;
            cur = nxt;
        }
        return prev;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals;
    for (int i = 0; i < n; ++i) {
        int x; cin >> x; vals.push_back(x);
    }
    // consume trailing 0 if present
    int sentinel;
    if (cin >> sentinel) {
        // ignore
    }
    // build linked list
    ListNode* head = nullptr;
    ListNode* tail = nullptr;
    for (int v : vals) {
        ListNode* node = new ListNode(v);
        if (!head) head = tail = node;
        else { tail->next = node; tail = node; }
    }
    Solution sol;
    ListNode* rev = sol.reverseList(head);
    // collect values
    vector<int> outVals;
    for (ListNode* cur = rev; cur; cur = cur->next) {
        outVals.push_back(cur->val);
    }
    cout << outVals.size() << "\n";
    for (size_t i = 0; i < outVals.size(); ++i) {
        cout << outVals[i] << "\n";
    }
    cout << 0 << "\n";
    return 0;
}
